php artisan prisoner:add '{"name":"Robert Webb","first_name":"Robert","last_name":"Webb","description":"Robert Webb was a Field Marshal of the New York chapter of the Black Panther Party and one of the original Panther 21 defendants — twenty-one New York Panthers arrested on April 2, 1969 and charged with conspiring to bomb New York police stations and Manhattan department stores. Webb was held in pretrial detention at New York jails for almost two years before being acquitted with the rest of the Panther 21 on all 156 counts on May 13, 1971 after a New York jury deliberation of less than 45 minutes.\n\nLess than a year later — on March 8, 1971, before the Panther 21 verdict — Webb was killed in Harlem in connection with the violent split between the East Coast and West Coast factions of the BPP that destroyed the party as a national organization. He was 22 years old. The Jericho Movement lists him among its ancestor political prisoners.","state":"New York","race":"Black","gender":"Male","birthdate":"1948-12-01","death_date":"1971-03-08","ideologies":["Black Liberation"],"affiliation":["Black Panther Party","Panther 21"],"in_custody":false,"released":false,"cases":[{"institution_name":"New York City jails","institution_state":"New York","charges":"Conspiracy to bomb New York City police stations, a railroad station, and Manhattan department stores (Panther 21 prosecution)","arrest_date":"1969-04-02","incarceration_date":"1969-04-02","release_date":"1971-05-13","sentence":"Held in pretrial detention approximately 23 months; killed three weeks before the Panther 21 acquittal verdict","convicted":"No — killed before the May 13, 1971 acquittal of the Panther 21"}]}'

php artisan prisoner:add '{"name":"Mark Clark","first_name":"Mark","last_name":"Clark","description":"Mark Clark was a 22-year-old leader of the Peoria, Illinois chapter of the Black Panther Party. Born in Peoria in 1947, he had organized the chapters Free Breakfast for Children program. On the night of December 3-4, 1969, he traveled to Chicago with other Panthers to attend a meeting at Fred Hamptons West Side apartment.\n\nIn the predawn hours of December 4, 1969, fourteen members of the Cook County States Attorneys office, working from a floor plan supplied by FBI informant William ONeal, conducted a no-knock raid on the apartment. Clark was killed by a single gunshot to the chest as he sat in a chair near the door, in what the official autopsy and ballistics reconstruction later established was the first shot fired in the raid — by police, not by Panthers, despite official initial claims of a Panther shootout. Fred Hampton was killed in his bed minutes later. A federal civil-rights lawsuit by the survivors and the Hampton and Clark families was eventually settled in 1982 for $1.85 million, paid jointly by the federal government, Cook County, and the City of Chicago. The Jericho Movement lists Clark among its ancestor political prisoners.","state":"Illinois","race":"Black","gender":"Male","birthdate":"1947-06-28","death_date":"1969-12-04","ideologies":["Black Liberation"],"affiliation":["Black Panther Party"],"in_custody":false,"released":false,"cases":[{"institution_name":"Cook County Jail","institution_state":"Illinois","charges":"Killed in a December 4, 1969 raid by the Cook County States Attorneys office and the Chicago Police Department, conducted on FBI intelligence supplied by informant William ONeal","arrest_date":"1969-12-04","incarceration_date":"1969-12-04","release_date":"1969-12-04","sentence":"Killed in the raid","convicted":"No — killed before any prosecution"}]}'

php artisan prisoner:add '{"name":"Abdul Olugbala Shakur","first_name":"Abdul Olugbala","last_name":"Shakur","aka":"Stanley Stocker-Worsham","description":"Abdul Olugbala Shakur, born Stanley Stocker-Worsham, is a New Afrikan political prisoner held in the California Department of Corrections and Rehabilitation under inmate number C48884. He has been incarcerated for more than four decades and is a longtime prison organizer, writer, and a leading voice from inside California prisons in the 2011 and 2013 California Pelican Bay Prisoner Hunger Strikes against indefinite solitary confinement, which drew tens of thousands of prisoners across the California system into participation. The Jericho Movement lists him among its current political prisoners. Detailed case background is being verified.","state":"California","race":"Black","gender":"Male","ideologies":["Black Liberation","Prison abolition"],"affiliation":["New Afrikan Independence Movement"],"inmate_number":"C48884","in_custody":true,"released":false,"cases":[{"institution_name":"California Department of Corrections and Rehabilitation","institution_state":"California","charges":"Case background being verified — listed by the Jericho Movement as a New Afrikan political prisoner","sentence":"Long-term California state prison sentence; involved in 2011 and 2013 California prisoner hunger strikes against indefinite solitary confinement","convicted":"Yes — California state conviction"}]}'

php artisan prisoner:add '{"name":"Shaka Shakur","first_name":"Shaka","last_name":"Shakur","description":"Shaka Shakur is a New Afrikan political prisoner held in the Indiana Department of Correction under inmate number 1996207. He has been incarcerated for decades and is a longtime prison organizer and writer whose essays have been published in support of the New Afrikan independence movement and the Jericho Movements campaign for amnesty for U.S. political prisoners. The Jericho Movement lists him among its current political prisoners. Detailed case background is being verified.","state":"Indiana","race":"Black","gender":"Male","ideologies":["Black Liberation","Prison abolition"],"affiliation":["New Afrikan Independence Movement"],"inmate_number":"1996207","in_custody":true,"released":false,"cases":[{"institution_name":"Indiana Department of Correction","institution_state":"Indiana","charges":"Case background being verified — listed by the Jericho Movement as a New Afrikan political prisoner","sentence":"Long-term Indiana state prison sentence","convicted":"Yes — Indiana state conviction"}]}'

