php artisan prisoner:add '{"name":"Georges Ibrahim Abdallah","first_name":"Georges","middle_name":"Ibrahim","last_name":"Abdallah","description":"Georges Ibrahim Abdallah is a Lebanese Communist who in 1987 was sentenced to life in a French prison for complicity in the 1982 Paris assassinations of U.S. Army Lieutenant Colonel Charles Robert Ray, the assistant U.S. military attache in France, and Israeli diplomat Yacov Barsimantov. The killings were claimed at the time by the Lebanese Armed Revolutionary Factions in retaliation for the U.S. and Israeli roles in the 1982 invasion of Lebanon. Abdallah did not himself fire the shots; he was prosecuted as the LARFs leader.\n\nHe became eligible for parole in 1999 and was approved for release multiple times by French parole boards across the following twenty-five years. Each time, the United States government and successive U.S. administrations intervened with the French government to block the release. He spent forty years in French prison — the longest-serving political prisoner in Western Europe — before he was finally ordered released by a French appeals court in November 2024 and deported to Lebanon on July 25, 2025. The Jericho Movement listed him among its international political prisoners. He is included in this database as one of the only people imprisoned for an extended period substantially at the insistence of the U.S. government.","state":"Lebanon","race":"Arab","gender":"Male","birthdate":"1951-04-02","ideologies":["Communism","Anti-imperialist","Lebanese resistance"],"affiliation":["Lebanese Armed Revolutionary Factions","Lebanese Communist Party"],"in_custody":false,"released":true,"cases":[{"institution_name":"Lannemezan Prison","institution_city":"Lannemezan","institution_state":"France","charges":"Complicity in the assassinations of U.S. Army Lieutenant Colonel Charles Robert Ray and Israeli diplomat Yacov Barsimantov in Paris in 1982","arrest_date":"1984-10-24","incarceration_date":"1987-02-28","release_date":"2025-07-25","sentence":"Life in French prison; served 40 years before deportation to Lebanon, with multiple parole approvals blocked at U.S. insistence","convicted":"Yes — French court verdict, February 1987"}]}'

